VALUES
  ('generalpolice-3218f787-moex-00176', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於社會工作理論中的「生態系統觀點（ecologicalperspective）」的陳述與說明，何者錯誤？', '["生態系統觀點認為案主所經歷的困境「生活中的問題」，乃是人的病態或性格的缺陷所致，社 會工作干預的標的對象主要是指個人", "生態系統觀點的重要假設是，一個人與生俱來就有能力與其所在的環境互動，有能力與其他人 發生關聯", "生態系統觀點主張，人類發展指的是正在成長中的個人與其環境間經年交流的結果，非單一的 個人特質因素可以完成發展的", "適應力是生態系統觀點的核心概念之一，指的是在個人與環境的交流過程中，個人與環境間相 互影響與回應以達到最佳的調和度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00177', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '保護性社會工作者在服務個案的過程中，常遭遇許多倫理議題的挑戰。當我們站在社會工作者與 個案關係的角度考量時，社會工作者下列何種作為，可能會違反社會工作的專業倫理？', '["社會工作者必須如實地告訴個案在保護性服務中，所可能會經歷的一切", "社會工作者願意付出時間陪伴個案", "社會工作者可在其專業裁量空間內，更多地考量個案的特殊需求", "社會工作者以完成上級交辦職務為唯一的考量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00178', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '社會工作者在團體工作中，常會鼓勵成員共同產生團體規範，並促成成員彼此互助與交流。這會 較屬於社會團體工作的那個階段？', '["團體初期", "團體形成期", "團體衝突期", "團體維持期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00179', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '隨著社會工作實務的發展，益發鼓勵社會工作者應肯定個案的優勢而非聚焦其劣勢，如此才能激 發個案更大的改變動力。這主要反映了下列那個社會工作實務取向？', '["生態系統社會工作", "優勢觀點社會工作", "認知行為取向社會工作", "精神分析社會工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00180', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '社會工作者在探究個案所面臨的關係議題時，常發現與其童年所經歷的依附關係有極大的關係。 若個案童年曾經歷父母未滿足其情感需求，且個案又因父母未予回應而時感痛苦與憤怒，這會是 依附理論中所描述的那種依附類型？', '["逃避型依附", "紊亂型依附", "焦慮型依附", "安全型依附"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00181', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '在社會工作理論的發展初期，大多借鑑心理學的知識。下列有關立基心理學的社會工作實務理論 描述，何者最為精確？', '["精神分析理論、認知行為學派與生態系統為此類理論的最佳代表", "立基心理學的社會工作實務理論是目前社會工作實務的主流", "精神分析理論提供了社會工作者短期介入的許多靈感", "心理學背景的社會工作實務理論，並未考慮個案的生活脈絡因素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00182', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '符號互動論學者對社會變遷有其獨特的理論解釋。符號互動論有關社會變遷的解釋並不包括下列 那些內容？', '["社會變遷總因人們對其行為與態度有了新的詮釋意義而展開", "態度與信仰的改變會加速社會的變遷", "新科技發明與全球化才是造成社會變遷的主要動力", "人們必須去適應社會變遷所帶來新的文化或想法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00183', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '犯罪作為偏差行為的重要類別，對此，已有社會學家認為犯罪是因階級、種族不平等才造成的結 果。這些社會學家主張唯有減少社會不平等才能更有效地解決犯罪。這樣的看法會比較偏向那種 社會學的觀點？', '["功能論", "符號互動論", "衝突論", "交換論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00184', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '在全球不平等議題上，部分社會學家強調高收入國家對低收入國家的長期剝削，甚至延續過往殖 民主義對貧窮國家的控制，如此才導致後者無法發展自立。這樣的看法會比較屬那種全球階層化 的理論？', '["世界體系理論", "依賴理論", "現代化理論", "全球化理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00185', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '在人們的社會化過程中，媒體扮演著重要的角色。社會學對於媒體的研究，並未發現媒體具下列 那個作用？', '["媒體中的暴力，常讓兒童失去對暴力的敏感度", "媒體可能夾帶許多社會價值與規範，並形塑我們對世界的看法", "媒體可能會與經濟利益相結合，最終形成「文化霸權」（culturalhegemony）的結果", "成人的暴力行為完全是由其童年媒體經驗所形塑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
